#saleListBox {
  font-family: inherit;
  padding: 4px;
}

.widget-header {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #469BC0;
  color: #FFFFFF;
  padding: 10px 14px;
  border-radius: 8px 8px 0 0;
  font-weight: 700;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.widget-header i {
  font-size: 14px;
}

#platformRow {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  background: #FFFFFF;
  border: 1px solid #E5E7EB;
  border-top: none;
}

#platformRow label {
  font-size: 11px;
  font-weight: 600;
  color: #64748B;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

#platformSelect {
  flex: 1;
  padding: 7px 10px;
  font-size: 13px;
  border: 1px solid #D1D5DB;
  border-radius: 6px;
  background: #FFFFFF;
}

#platformSelect:focus {
  outline: none;
  border-color: #469BC0;
  box-shadow: 0 0 0 2px rgba(70, 155, 192, 0.15);
}

#saleTable {
  width: 100%;
  border-collapse: collapse;
  background: #FFFFFF;
  border: 1px solid #E5E7EB;
  border-top: none;
}

#saleTable th {
  text-align: left;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  color: #64748B;
  font-weight: 600;
  padding: 8px 10px;
  border-bottom: 1px solid #E5E7EB;
  background: #F8FAFC;
}

#saleTable td {
  padding: 8px 10px;
  font-size: 12px;
  border-bottom: 1px solid #F1F5F9;
  color: #1F2937;
}

.priceInput {
  width: 70px;
  padding: 5px 7px;
  font-size: 12px;
  border: 1px solid #D1D5DB;
  border-radius: 6px;
}

.priceInput:focus {
  outline: none;
  border-color: #469BC0;
  box-shadow: 0 0 0 2px rgba(70, 155, 192, 0.15);
}

.fee-cell {
  color: #64748B;
}

.removeBtn {
  background: none;
  border: none;
  color: #DC2626;
  font-size: 16px;
  cursor: pointer;
  line-height: 1;
  padding: 4px 6px;
}

.removeBtn:hover {
  color: #991B1B;
}

.empty-row {
  text-align: center;
  color: #94A3B8;
  padding: 18px 0;
  font-size: 12px;
}

#saleTotalRow {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 14px;
  background: #F8FAFC;
  border: 1px solid #E5E7EB;
  border-top: none;
  font-weight: 700;
  font-size: 14px;
  color: #05042E;
}

#processOrderBtn {
  width: 100%;
  margin-top: 10px;
  padding: 10px;
  background: #00C170;
  color: #05042E;
  font-weight: 700;
  font-size: 13px;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: opacity 0.15s;
}

#processOrderBtn:hover {
  opacity: 0.9;
}

