function escHtml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function render() {
  const m = appsmith.model || {};
  const platforms = Array.isArray(m.platforms) ? m.platforms : [];
  const items = Array.isArray(m.saleList) ? m.saleList : [];
  const selectedPlatform = m.selectedPlatform || '';
  const select = document.getElementById('platformSelect');
  if (select.options.length <= 1 && platforms.length > 0) {
    platforms.forEach(function (p) {
      const opt = document.createElement('option');
      opt.value = p.platform;
      opt.textContent = p.platform;
      select.appendChild(opt);
    });
  }
  if (select.value !== selectedPlatform) select.value = selectedPlatform;
  const tbody = document.getElementById('saleTbody');
  if (!items.length) {
    tbody.innerHTML = '<tr><td colspan="6" class="empty-row">No items added yet.</td></tr>';
    document.getElementById('saleTotal').textContent = '£0.00';
    return;
  }
  let total = 0;
  tbody.innerHTML = items.map(function (item, idx) {
    const price = Number(item.sell_price || 0);
    total += price;
    return '<tr>' + '<td>' + escHtml(item.asset_ref) + '</td>' + '<td>' + escHtml(item.item_type_name) + '</td>' + '<td>' + escHtml(item.make_name) + ' ' + escHtml(item.model_name) + '</td>' + '<td>' + escHtml(item.serial_number) + '</td>' + '<td><input type="number" step="0.01" class="priceInput" data-idx="' + idx + '" value="' + price.toFixed(2) + '" /></td>' + '<td><button class="removeBtn" data-id="' + escHtml(item.asset_id) + '">&times;</button></td>' + '</tr>';
  }).join('');
  document.getElementById('saleTotal').textContent = '£' + total.toFixed(2);
  Array.from(document.getElementsByClassName('priceInput')).forEach(function (input) {
    input.addEventListener('focus', function () {
      input.select();
    });
    input.onchange = function () {
      const idx = Number(input.dataset.idx);
      appsmith.updateModel({
        priceUpdate: {
          idx: idx,
          value: Number(input.value)
        }
      });
      appsmith.triggerEvent('onPriceChange');
    };
  });
  Array.from(document.getElementsByClassName('removeBtn')).forEach(function (btn) {
    btn.onclick = function () {
      appsmith.updateModel({
        removeId: btn.dataset.id
      });
      appsmith.triggerEvent('onRemoveItem');
    };
  });
}
appsmith.onReady(function () {
  render();
  document.getElementById('platformSelect').onchange = function () {
    appsmith.updateModel({
      selectedPlatform: this.value
    });
    appsmith.triggerEvent('onPlatformChange');
  };
  document.getElementById('processOrderBtn').onclick = function () {
    appsmith.triggerEvent('onProcessOrder');
  };
});
appsmith.onModelChange(render);

